const nums = [...html.matchAll(/[?&]page=(\d+)/g)].map(m => parseInt(m[1],10)).filter(n => !isNaN(n));
const maxPage = nums.length ? Math.min(Math.max(...nums), 50) : 1;
const out = []; for (let p = 1; p <= maxPage; p++) out.push({ json: { page: p } });
