// Canalcar - transform: tarjetas (data-coche-id/data-precio/data-url) -> UPSERT
const httpOut = $input.item.json;
const html = typeof httpOut === 'string' ? httpOut : String(httpOut.data || httpOut.body || '');
function num(s){ const n=parseInt(String(s).replace(/[^0-9]/g,''),10); return isNaN(n)?null:n; }
function attr(c,name){ const m=c.match(new RegExp(name+'="([^"]*)"','i')); return m?m[1]:''; }
function cap(s){ return String(s).split('-').map(w=>w?w[0].toUpperCase()+w.slice(1):w).join(' '); }
function esc(v){ if(v===null||v===undefined) return 'NULL'; if(typeof v==='number') return isNaN(v)?'NULL':String(v); return "'"+String(v).replace(/'/g,"''")+"'"; }
function normFuel(s){ s=String(s).toLowerCase(); if(/gnc|glp|gas natural/.test(s)) return 'Gas'; if(/eléctric|electric/.test(s)) return 'Eléctrico'; if(/híbrid|hibrid/.test(s)) return 'Híbrido'; if(/diésel|diesel/.test(s)) return 'Diesel'; if(/gasolina/.test(s)) return 'Gasolina'; return ''; }
function normGear(s){ s=String(s).toLowerCase(); if(/autom/.test(s)) return 'Automatica'; if(/manual/.test(s)) return 'Manual'; return ''; }
const marks = [...html.matchAll(/data-coche-id="(\d+)"/g)];
const seen = new Set(); const rows = [];
for (let i=0;i<marks.length;i++){
  const startPos=Math.max(0,marks[i].index-400);
  const endPos=(i+1<marks.length)?marks[i+1].index:marks[i].index+2200;
  const chunk=html.slice(startPos,endPos);
  const id=marks[i][1]; if(seen.has(id)) continue; seen.add(id);
  const dataUrl=attr(chunk,'data-url'); if(!dataUrl) continue;
  const parts=dataUrl.split('/').filter(Boolean);
  const brand=cap(parts[1]||''); const model=cap(parts[2]||'');
  const pf=parseFloat(attr(chunk,'data-precio')); const price=isNaN(pf)?null:Math.round(pf);
  const url='https://www.canalcar.es'+dataUrl;
  const img=(chunk.match(/<img[^>]+src="(https:\/\/content\.canalcar[^"]+)"/i)||[])[1]||'';
  const text=chunk.replace(/<[^>]+>/g,' ').replace(/&amp;/g,'&').replace(/\s+/g,' ').trim();
  const year=(text.match(/\b(20\d{2}|19\d{2})\b/)||[])[1]||null;
  const km=num((text.match(/([0-9.]+)\s*kms?/i)||[])[1]);
  const fuel=normFuel((text.match(/GNC|GLP|Di[eé]sel|Gasolina|El[eé]ctric[oa]|H[ií]brid[oa]/i)||[])[0]);
  const trans=normGear((text.match(/Manual|Autom[aá]tic[oa]/i)||[])[0]);
  const title=attr(chunk,'data-title');
  let version='';
  const vm=text.match(new RegExp((title||(brand+' '+model)).replace(/[.*+?^${}()|[\]\\]/g,'\\$&')+'\\s+([^|0-9][^|]*?)\\s*(20\\d{2}|19\\d{2})','i'));
  if(vm) version=vm[1]; else version=cap(parts[3]||'');
  version=version.replace(/\bundefined\b/gi,'').replace(/\s+\d+\s*$/,'').replace(/\s+/g,' ').trim().slice(0,80);
  if(!price) continue;
  const t=((title||(brand+' '+model))+' '+version).replace(/\s+/g,' ').trim();
  const imagesJson=(img?JSON.stringify([img]):'[]').replace(/'/g,"''");
  const row='('+esc('cnc_'+id)+", 'canalcar', "+esc(url)+', '+esc(t)+', '+esc(brand)+', '+esc(model)+', '+esc(version)+', '+
    (year!=null?String(year):'NULL')+', '+(km!=null?String(km):'NULL')+', '+(price!=null?String(price):'NULL')+', '+
    esc(fuel)+', '+esc(trans)+', '+esc(img)+", '"+imagesJson+"', 'profesional', 'compra', NOW(), NOW(), NOW())";
  rows.push(row);
}
if(!rows.length) return [{ json:{ sql:null, count:0 } }];
const cols='id, portal, url, title, brand, model, version, year, mileage, price, fuel, transmission, image_url, images, seller_type, listing_type, first_seen_at, scraped_at, last_seen_at';
const onConflict="ON CONFLICT (id) DO UPDATE SET url=EXCLUDED.url, title=EXCLUDED.title, price=EXCLUDED.price, mileage=EXCLUDED.mileage, image_url=COALESCE(NULLIF(moveadvisor_market_offers.image_url,''), EXCLUDED.image_url), last_seen_at=NOW(), updated_at=NOW()";
const sql='INSERT INTO moveadvisor_market_offers ('+cols+') VALUES '+rows.join(', ')+' '+onConflict;
return [{ json:{ sql:sql, count:rows.length } }];
